// Script Continued Below
// STRY0158283 - (DEFECT) As a basic user, users are able to see ALL task logs, email request, tasks, and response logs even of tasks they shouldn't
var responseTask = current.getValue("u_task") || '';
// STRY0146507 - Certification Failed Test Resutls - NOT FIXING - Task permissions drives Task Response permissions
var grResponseTask = new GlideRecord("x_153465_discovert_route_task_instance");
var allow = false;
if(responseTask !=''){
	if(grResponseTask.get(responseTask)){
		allow = grResponseTask.canRead();
	}
}
answer = allow;
